class Solution {
public:
    vector<int> maximumCount(vector<int>& nums, vector<vector<int>>& queries) {
        int n = nums.size();
        vector<int> primes;
        for (int i = 2; i <= 10000; i++) {
            bool isPrime = true;
            for (int j = 2; j * j <= i; j++) {
                if (i % j == 0) {
                    isPrime = false;
                    break;
                }
            }
            if (isPrime) primes.push_back(i);
        }
        vector<int> distinctPrimes(n);
        for (int i = 0; i < n; i++) {
            distinctPrimes[i] = countPrimes(nums[i], primes);
        }
        vector<int> result;
        for (auto& query : queries) {
            int idx = query[0], val = query[1];
            nums[idx] = val;
            int left = 0, right = n - 1;
            while (left < right) {
                int mid = left + (right - left) / 2;
                if (countPrimes(nums[mid], primes) + countPrimes(nums[n - 1], primes) > countPrimes(nums[left], primes) + countPrimes(nums[n - 1] - nums[left] - 1, primes)) {
                    left = mid + 1;
                } else {
                    right = mid;
                }
            }
            result.push_back(countPrimes(nums[left], primes) + countPrimes(nums[n - 1] - nums[left] - 1, primes));
        }
        return result;
    }

    int countPrimes(int num, vector<int>& primes) {
        int count = 0;
        for (int prime : primes) {
            if (prime > num) break;
            if (num % prime == 0) count++;
        }
        return count;
    }
};
